from minivess.pipeline.multi_strategy_inference import MultiStrategyInferenceRunner

def _evaluate_single_model_on_all(model, dataloaders_dict, eval_config, *, model_name, output_dir=None):
    runner = MultiStrategyInferenceRunner(
        strategies=eval_config.inference_strategies,
        num_classes=2,
    )
    # runner.run_all_strategies() returns {strategy_name: {metric_name: value}}
    # Primary strategy metrics: bare keys. Non-primary: "strategy_name/metric_name"
    all_results = {}
    for strategy_name, metrics in runner.run_all_strategies(model, dataloaders_dict).items():
        strategy = next(s for s in eval_config.inference_strategies if s.name == strategy_name)
        if strategy.is_primary:
            all_results.update(metrics)
        else:
            all_results.update({f"{strategy_name}/{k}": v for k, v in metrics.items()})
    return all_results
